//!
//! Thin newtype over `backbone_orm::GenericCrudRepository<WorkOrderItem, backbone_orm::SoftDelete>`.
//! All standard CRUD methods are available via `Deref`.

use anyhow::Result;
use rust_decimal::Decimal;
use sqlx::{PgPool, Row};
use uuid::Uuid;

use backbone_orm::company_scope;

use crate::domain::entity::WorkOrderItem;

/// Table name for WorkOrderItem entities
pub const TABLE_NAME: &str = "manufacturing.work_order_items";

/// Repository for WorkOrderItem entities.
